// Token protection — only requests with ?token=ACCESS_TOKEN can access the form
function requireToken(req, res, next) {
  const token = req.query.token || req.body?.token;
  if (token === ACCESS_TOKEN) return next();
  res.status(403).send(`<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <title>Access Restricted</title>
  <style>
    body { font-family: Arial, sans-serif; background: #f0f2f5; display: flex; align-items: center; justify-content: center; min-height: 100vh; }
    .box { background: #fff; border-radius: 10px; padding: 48px 40px; text-align: center; max-width: 420px; box-shadow: 0 4px 24px rgba(0,0,0,0.10); }
    h2 { color: #1A2744; margin-bottom: 12px; }
    p { color: #666; font-size: 15px; }
  </style>
</head>
<body>
  <div class="box">
    <h2>Access Restricted</h2>
    <p>This page requires an access token. Please use the link provided by Option 10.</p>
  </div>
</body>
</html>`);
}

